        {"id": 29, "type": "matching", "instruction": "Spojite parove", "content": {"pairs": [["opisivati / opisati", "imperfective / perfective: to describe / to have described"], ["razvijati / razviti", "imperfective / perfective: to develop / to have developed"]]}, "answer": "matched", "hint": "Vidski parovi"},
        {"id": 30, "type": "matching", "instruction": "Spojite parove", "content": {"pairs": [["jer", "because – causal conjunction"], ["iako", "although – concessive conjunction"], ["kako bi", "in order to – final conjunction"]]}, "answer": "matched", "hint": "Veznici"},
        # IDs 31-40: translate EN→BS
        {"id": 31, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Linguistics studies the structure of language."}, "answer": "Lingvistika proučava strukturu jezika.", "hint": "lingvistika = linguistics, proučava = studies"},
        {"id": 32, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Semantics deals with the meaning of words."}, "answer": "Semantika se bavi značenjem riječi.", "hint": "bavi se = deals with, značenje = meaning"},
        {"id": 33, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Language changes because society changes too."}, "answer": "Jezik se mijenja jer se mijenja i društvo.", "hint": "jer = because, mijenja se = changes"},
        {"id": 34, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Although they are related, they differ."}, "answer": "Iako su srodne, razlikuju se.", "hint": "iako = although, razlikuju se = they differ"},
        {"id": 35, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Nominalisation converts verbs into nouns."}, "answer": "Nominalizacija pretvara glagole u imenice.", "hint": "pretvara = converts, imenice = nouns"},
        {"id": 36, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "The professor said that language is a system."}, "answer": "Profesor je rekao da je jezik sistem.", "hint": "Neupravni govor: rekao da..."},
        {"id": 37, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Multilingualism is an increasingly valued competence."}, "answer": "Višejezičnost je sve cijenjenija kompetencija.", "hint": "sve cijenjenija = increasingly valued"},
        {"id": 38, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Linguists describe language in order to understand it better."}, "answer": "Lingvisti opisuju jezik kako bi ga bolje razumjeli.", "hint": "kako bi = in order to"},
        {"id": 39, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Discourse analysis examines language above the sentence level."}, "answer": "Diskursna analiza ispituje jezik iznad razine rečenice.", "hint": "iznad razine = above the level"},
        {"id": 40, "type": "translate", "instruction": "Prevedite na bosanski", "content": {"text": "Linguistic identity is closely tied to cultural identity."}, "answer": "Jezični identitet usko je vezan za kulturni identitet.", "hint": "usko vezan = closely tied"},
        # IDs 41-50: translate_en BS→EN
        {"id": 41, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Fonologija proučava glasovni sistem jednog jezika."}, "answer": "Phonology studies the sound system of a language.", "hint": "glasovni sistem = sound system"},
        {"id": 42, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Semiotika je nauka o znakovima i simbolima."}, "answer": "Semiotics is the science of signs and symbols.", "hint": "znakovi = signs, simboli = symbols"},
        {"id": 43, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Jezična politika određuje status službenih jezika."}, "answer": "Language policy determines the status of official languages.", "hint": "određuje = determines, službeni = official"},
        {"id": 44, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Konačno sam proučio sintaksu do detalja."}, "answer": "I have finally studied syntax in detail.", "hint": "Svršeni vid: proučio = have studied"},
        {"id": 45, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Dijalekti odražavaju bogatu kulturnu raznolikost."}, "answer": "Dialects reflect rich cultural diversity.", "hint": "odražavaju = reflect, raznolikost = diversity"},
        {"id": 46, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Pitao je hoćemo li učiti lingvistiku."}, "answer": "He asked whether we would study linguistics.", "hint": "Neupravno pitanje: hoće li = whether"},
        {"id": 47, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Ukoliko se kontekst promijeni, mijenja se i značenje."}, "answer": "If the context changes, the meaning changes too.", "hint": "ukoliko = if"},
        {"id": 48, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Leksikologija proučava vokabular jednog jezika."}, "answer": "Lexicology studies the vocabulary of a language.", "hint": "vokabular = vocabulary"},
        {"id": 49, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Morfologija analizira građu i tvorbu riječi."}, "answer": "Morphology analyses the structure and formation of words.", "hint": "građa = structure, tvorba = formation"},
        {"id": 50, "type": "translate_en", "instruction": "Prevedite na engleski", "content": {"text": "Jezična promjena je prirodan i neizbježan proces."}, "answer": "Language change is a natural and inevitable process.", "hint": "neizbježan = inevitable"},
        # IDs 51-60: multiple_choice
        {"id": 51, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta proučava semantika?", "options": ["glasovni sistem", "značenje riječi i rečenica", "rečenični red", "tvorbu riječi"]}, "answer": "značenje riječi i rečenica", "hint": "Semantika = meaning"},
        {"id": 52, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Koji veznik izražava uzrok?", "options": ["iako", "jer", "ako", "kako bi"]}, "answer": "jer", "hint": "Uzročni veznik = causal conjunction"},
        {"id": 53, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta je nominalizacija?", "options": ["pretvaranje imenica u glagole", "pretvaranje glagola i pridjeva u imenice", "tvorba pridjeva", "promjena rečeničnog reda"]}, "answer": "pretvaranje glagola i pridjeva u imenice", "hint": "Nominalizacija = noun + process"},
        {"id": 54, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Koji je svršeni vid od 'proučavati'?", "options": ["proučavati", "proučiti", "proučavanjem", "proučavano"]}, "answer": "proučiti", "hint": "Svršeni vid = perfective aspect"},
        {"id": 55, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta opisuje fonologija?", "options": ["rečeničnu strukturu", "značenje", "glasovni sistem", "vokabular"]}, "answer": "glasovni sistem", "hint": "Fon- = sound"},
        {"id": 56, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Koji veznik izražava dopuštanje (concessive)?", "options": ["jer", "ako", "kako bi", "iako"]}, "answer": "iako", "hint": "Premda / iako = although"},
        {"id": 57, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta je višejezičnost?", "options": ["znanje jednog jezika", "sposobnost upotrebe više jezika", "proučavanje dijalekta", "jezična politika"]}, "answer": "sposobnost upotrebe više jezika", "hint": "Više = multiple, jezičnost = languageness"},
        {"id": 58, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Što proučava pragmatika?", "options": ["glasove", "rečenicu", "upotrebu jezika u kontekstu", "tvorbu imenica"]}, "answer": "upotrebu jezika u kontekstu", "hint": "Pragma = action/context"},
        {"id": 59, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Kako se tvori neupravni govor od 'Jezik je sistem.'?", "options": ["Rekao je da jezik je sistem.", "Rekao je da je jezik sistem.", "Rekao je jezik je sistem.", "Rekao je jezik sistem."]}, "answer": "Rekao je da je jezik sistem.", "hint": "da + inverzija: da je..."},
        {"id": 60, "type": "multiple_choice", "instruction": "Odaberite tačan odgovor", "content": {"question": "Šta je dijalekt?", "options": ["standardni jezik", "regionalna varijanta jednog jezika", "strani jezik", "pisani jezik"]}, "answer": "regionalna varijanta jednog jezika", "hint": "Dia- = through/across, lect = speech"},
