        {"id": 68, "type": "word_form", "instruction": "Upišite odgovarajući oblik", "content": {"sentence": "Profesor je rekao da _____ jezik sistem. (biti – prezent 3. l. jd.)", "base_word": "biti"}, "answer": "je", "hint": "Kratki oblik pomoćnog glagola"},
        {"id": 69, "type": "word_form", "instruction": "Upišite odgovarajući oblik", "content": {"sentence": "Lingvistika proučava _____ jezika. (struktura – akuzativ)", "base_word": "struktura"}, "answer": "strukturu", "hint": "Akuzativ imenice ženskog roda na -a"},
        {"id": 70, "type": "word_form", "instruction": "Upišite odgovarajući oblik", "content": {"sentence": "Pitao je _____ li učiti lingvistiku. (htjeti – futur III. lice)", "base_word": "htjeti"}, "answer": "hoćemo", "hint": "Neupravno pitanje: hoćemo li..."},
