        {"id": 7, "question": "Šta opisuje sintaksa?", "options": ["glasovni sistem", "vokabular", "pravila raspoređivanja riječi u rečenici", "tvorbu novih riječi"], "correct_answer": 2, "explanation": "Sintaksa proučava pravila po kojima se riječi slažu u fraze i rečenice.", "question_type": "vocabulary"},
